def split_lowerstring(s: str):
    """
    Split a string at lowercase letters.
    The split occurs before each lowercase letter, but the lowercase letter itself is kept in the resulting parts.
    """
    if not s:
        return []

    parts = []
    current = []

    for i, char in enumerate(s):
        if char.islower():
            if current:
                parts.append(''.join(current))
                current = []
            # The lowercase letter stays in the next segment or is part of the current segment if followed by uppercase
        else:
            current.append(char)

    if current:
        parts.append(''.join(current))

    return parts

