def split_lowerstring(s: str) -> list:
    """
    Split a string at lowercase letters, excluding the first character if it's lowercase.

    Args:
        s (str): The input string to split.

    Returns:
        list: A list of substrings that were separated by lowercase letters.
    """
    if not s:
        return []

    parts = []
    current = s[0]

    for i in range(1, len(s)):
        if s[i].islower():
            if current:
                parts.append(current)
                current = ""
            parts.append(s[i])
        else:
            current += s[i]

    if current:
        parts.append(current)

    return parts

