def func(arrays, k):
    if not arrays:
        return []

    # Count frequencies
    freq = {}
    for lst in arrays:
        for num in lst:
            freq[num] = freq.get(num, 0) + 1

    # Use a min-heap to keep track of top k elements
    heap = []
    for num, count in freq.items():
        heapq.heappush(heap, (count, num))

    # Pop k times to get top k most frequent
    result = []
    for _ in range(k):
        if heap:
            count, num = heapq.heappop(heap)
            result.append(num)

    return result

