def max_len_sub(arr, k):
    if not arr:
        return 0
    if k == 0:
        return len(arr)

    # Sort the array to consider all subsequences
    arr_sorted = sorted(arr)

    # Dynamic programming approach
    # dp[i] = max length of subsequence ending at index i with adjacent difference k
    n = len(arr_sorted)
    dp = [1] * n

    for i in range(n):
        for j in range(i):
            if abs(arr_sorted[i] - arr_sorted[j]) == k:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)

